good-example.code-block:
package org.acme.orders.domain;

import io.quarkus.mongodb.panache.PanacheMongoEntity;
import io.quarkus.mongodb.panache.common.MongoEntity;
import org.bson.codecs.pojo.annotations.BsonProperty;
import java.time.Instant;

@MongoEntity(collection = "orders")
public class OrderDocument extends PanacheMongoEntity {
    @BsonProperty("order_number")
    public String orderNumber;
    public String customerId;
    public Instant createdAt;
}

bad-example.code-block:
package org.acme.orders.domain;

import io.quarkus.mongodb.panache.PanacheMongoEntity;

// Bad: no explicit collection/schema hints for critical fields
public class OrderDocument extends PanacheMongoEntity {
    public Object payload;
}

good-example.code-block:
package org.acme.orders.repository;

import org.acme.orders.domain.OrderDocument;
import io.quarkus.mongodb.panache.PanacheMongoRepository;
import jakarta.enterprise.context.ApplicationScoped;
import java.util.Optional;

@ApplicationScoped
public class OrderRepository implements PanacheMongoRepository<OrderDocument> {
    public Optional<OrderDocument> findByOrderNumber(String orderNumber) {
        return find("orderNumber", orderNumber).firstResultOptional();
    }
}

bad-example.code-block:
package org.acme.orders.repository;

import jakarta.enterprise.context.ApplicationScoped;

@ApplicationScoped
public class BadOrderRepository {
    // Bad: hand-built query strings from user input, prone to injection and syntax errors
    String query(String input) { 
        return "{ orderNumber: '" + input + "' }"; 
    }
}

good-example.code-block:
package org.acme.orders.service;

import org.acme.orders.domain.OrderDocument;
import org.acme.orders.repository.OrderRepository;
import com.mongodb.MongoWriteException;
import com.mongodb.MongoTimeoutException;
import com.mongodb.ErrorCategory;
import jakarta.enterprise.context.ApplicationScoped;

@ApplicationScoped
public class OrderService {
    private final OrderRepository repository;

    public OrderService(OrderRepository repository) {
        this.repository = repository;
    }

    public void createOrder(OrderDocument document) {
        try {
            repository.persist(document);
        } catch (MongoWriteException ex) {
            if (ex.getError().getCategory() == ErrorCategory.DUPLICATE_KEY) {
                throw new IllegalStateException("Order number already exists", ex);
            }
            throw ex;
        } catch (MongoTimeoutException ex) {
            throw new IllegalStateException("Transient Mongo timeout, consider retry", ex);
        }
    }
}

bad-example.code-block:
package org.acme.orders.service;

import org.acme.orders.domain.OrderDocument;
import org.acme.orders.repository.OrderRepository;
import jakarta.enterprise.context.ApplicationScoped;

@ApplicationScoped
public class BadOrderService {
    private final OrderRepository repository;

    public BadOrderService(OrderRepository repository) {
        this.repository = repository;
    }

    public void createOrder(OrderDocument document) {
        try {
            repository.persist(document);
        } catch (Exception ex) {
            // Bad: generic catch + ignore, hiding data loss
        }
    }
}
